/**
 * Handler 3: Drift Detection
 *
 * Hashes rule files and compares to cached hashes from last session.
 * Reports which files changed, were added, or removed between sessions.
 */

import { logHook, fnv1aHash } from '../lib/common.js';
import { existsSync, readFileSync } from 'node:fs';
import { basename, join } from 'node:path';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { getProjectDir } from '../lib/paths.js';
import type { LoadedFile, DriftCache } from './types.js';

const HOOK_NAME = 'instructions-loaded/drift-detection';

function getDriftCachePath(): string {
  return join(getProjectDir(), '.claude', 'feedback', 'instruction-drift-cache.json');
}

function loadDriftCache(): DriftCache | null {
  const cachePath = getDriftCachePath();
  try {
    if (existsSync(cachePath)) {
      return JSON.parse(readFileSync(cachePath, 'utf8')) as DriftCache;
    }
  } catch {
    // Corrupted cache — rebuild
  }
  return null;
}

function saveDriftCache(hashes: Record<string, string>): void {
  const cache: DriftCache = {
    version: '1.0',
    lastSession: new Date().toISOString(),
    fileHashes: hashes,
  };
  try {
    atomicWriteSync(getDriftCachePath(), JSON.stringify(cache, null, 2));
  } catch (err) {
    logHook(HOOK_NAME, `Failed to save drift cache: ${err}`, 'warn');
  }
}

export function driftDetection(filesLoaded: LoadedFile[]): string | null {
  const currentHashes: Record<string, string> = {};

  for (const f of filesLoaded) {
    try {
      const content = readFileSync(f.path, 'utf8');
      // Use relative-ish key to avoid basename collisions across directories
      const key = f.path.includes('.claude/') ? f.path.slice(f.path.indexOf('.claude/')) : basename(f.path);
      currentHashes[key] = fnv1aHash(content);
    } catch {
      // Skip unreadable files
    }
  }

  const previousCache = loadDriftCache();
  saveDriftCache(currentHashes);

  if (!previousCache) {
    logHook(HOOK_NAME, 'Drift detection: first run, baseline saved');
    return null;
  }

  const changed: string[] = [];
  const added: string[] = [];
  const removed: string[] = [];

  for (const [name, hash] of Object.entries(currentHashes)) {
    if (!(name in previousCache.fileHashes)) {
      added.push(name);
    } else if (previousCache.fileHashes[name] !== hash) {
      changed.push(name);
    }
  }

  for (const name of Object.keys(previousCache.fileHashes)) {
    if (!(name in currentHashes)) {
      removed.push(name);
    }
  }

  const totalChanges = changed.length + added.length + removed.length;
  if (totalChanges === 0) {
    logHook(HOOK_NAME, 'Drift detection: no changes since last session');
    return null;
  }

  logHook(HOOK_NAME, `Drift detection: ${totalChanges} changes since last session`);

  const parts = [`[Instruction Drift] Changes since last session (${previousCache.lastSession.split('T')[0]}):`];
  if (changed.length > 0) parts.push(`  Modified: ${changed.join(', ')}`);
  if (added.length > 0) parts.push(`  Added: ${added.join(', ')}`);
  if (removed.length > 0) parts.push(`  Removed: ${removed.join(', ')}`);

  return parts.join('\n');
}
